#!/bin/bash
# cloud-run-deploy.sh: Deploy quantized weight inference to Google Cloud Run
# Serverless inference with automatic scaling, per-request GPU allocation

set -e

# Configuration
PROJECT_ID="${GCP_PROJECT:-forkjoin-ai}"
REGION="${GCP_REGION:-us-central1}"
SERVICE_NAME="gnosis-quantized-inference"
IMAGE_REPO="gcr.io/${PROJECT_ID}/gnosis"
IMAGE_TAG="latest"
FULL_IMAGE="${IMAGE_REPO}:${IMAGE_TAG}"

# Color output
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
NC='\033[0m'

echo -e "${YELLOW}=== Google Cloud Run Deployment ===${NC}"
echo "Project: $PROJECT_ID"
echo "Region: $REGION"
echo "Service: $SERVICE_NAME"
echo "Image: $FULL_IMAGE"
echo ""

# Step 1: Authenticate with GCP
echo -e "${YELLOW}[1/6]${NC} Authenticating with GCP..."
gcloud auth application-default print-access-token > /dev/null 2>&1 || {
    echo -e "${RED}Error: Not authenticated. Run: gcloud auth application-default login${NC}"
    exit 1
}
echo -e "${GREEN}✓ Authenticated${NC}"

# Step 2: Build Docker image
echo -e "${YELLOW}[2/6]${NC} Building Docker image..."
docker build -f Dockerfile.quantized-weights \
    -t "${FULL_IMAGE}" \
    --build-arg CUDA_VERSION=12.2.2 \
    . || {
    echo -e "${RED}Error: Docker build failed${NC}"
    exit 1
}
echo -e "${GREEN}✓ Docker image built${NC}"

# Step 3: Push to Container Registry
echo -e "${YELLOW}[3/6]${NC} Pushing image to Google Container Registry..."
docker push "${FULL_IMAGE}" || {
    echo -e "${RED}Error: Docker push failed${NC}"
    exit 1
}
echo -e "${GREEN}✓ Image pushed: ${FULL_IMAGE}${NC}"

# Step 4: Deploy to Cloud Run
echo -e "${YELLOW}[4/6]${NC} Deploying to Cloud Run..."
gcloud run deploy "${SERVICE_NAME}" \
    --image="${FULL_IMAGE}" \
    --platform=managed \
    --region="${REGION}" \
    --memory=24Gi \
    --cpu=8 \
    --gpu=1 \
    --gpu-type=nvidia-l4 \
    --no-gpu-zonal-redundancy \
    --no-cpu-throttling \
    --timeout=3600 \
    --min-instances=0 \
    --max-instances=3 \
    --max=3 \
    --concurrency=10 \
    --port=8000 \
    --no-allow-unauthenticated \
    --service-account="${SERVICE_NAME}@${PROJECT_ID}.iam.gserviceaccount.com" \
    --set-env-vars="MODEL_NAME=llama,WEIGHTS_PATH=/weights/quantized,LOG_LEVEL=INFO" \
    --project="${PROJECT_ID}" || {
    echo -e "${RED}Error: Cloud Run deployment failed${NC}"
    exit 1
}
echo -e "${GREEN}✓ Deployed to Cloud Run${NC}"

# Step 5: Get service URL
echo -e "${YELLOW}[5/6]${NC} Retrieving service URL..."
SERVICE_URL=$(gcloud run services describe "${SERVICE_NAME}" \
    --platform=managed \
    --region="${REGION}" \
    --format='value(status.url)' \
    --project="${PROJECT_ID}")

echo -e "${GREEN}✓ Service URL: ${SERVICE_URL}${NC}"

# Step 6: Test endpoint
echo -e "${YELLOW}[6/6]${NC} Testing inference endpoint..."
sleep 5  # Wait for service to be ready

HEALTH_RESPONSE=$(curl -s -w "\n%{http_code}" \
    -H "Authorization: Bearer $(gcloud auth application-default print-access-token)" \
    "${SERVICE_URL}/health" || echo "000")

HTTP_CODE=$(echo "$HEALTH_RESPONSE" | tail -n1)

if [ "$HTTP_CODE" = "200" ]; then
    echo -e "${GREEN}✓ Service is healthy (HTTP 200)${NC}"
else
    echo -e "${YELLOW}⚠ Service returned HTTP $HTTP_CODE (still starting up, check again in 30s)${NC}"
fi

echo ""
echo -e "${GREEN}=== Deployment Complete ===${NC}"
echo ""
echo "Service details:"
echo "  Name: $SERVICE_NAME"
echo "  URL: $SERVICE_URL"
echo "  Region: $REGION"
echo ""
echo "Next steps:"
echo "  1. Verify inference:"
echo "     curl -H 'Authorization: Bearer \$(gcloud auth application-default print-access-token)' \\"
echo "          -X POST $SERVICE_URL/infer \\"
echo "          -H 'Content-Type: application/json' \\"
echo "          -d '{\"model\": \"llama\", \"prompt\": \"Hello, World!\"}'"
echo ""
echo "  2. Monitor logs:"
echo "     gcloud run logs read $SERVICE_NAME --region=$REGION --limit=50"
echo ""
echo "  3. Check metrics:"
echo "     gcloud monitoring dashboards create --config-from-file=cloud-run-dashboard.json"
echo ""

# Save deployment info
cat > ".deployment-${SERVICE_NAME}.txt" <<EOF
# Cloud Run Deployment Info
Service Name: $SERVICE_NAME
Project: $PROJECT_ID
Region: $REGION
Image: $FULL_IMAGE
URL: $SERVICE_URL
Deployed: $(date -u +%Y-%m-%dT%H:%M:%SZ)
EOF

echo -e "${GREEN}Deployment info saved to .deployment-${SERVICE_NAME}.txt${NC}"
